+    }
+
+    #[test]
+    fn nick_complete_strips_voice_sigil_from_nick() {
+        let mut app = make_app_with_nicks(&["+bob"]);
+        app.editor.text = "bo".to_string();
+        app.editor.cursor = 2;
+        try_nick_complete(&mut app);
